// Construye el prompt y el body para la API de OpenAI segun la accion.
const b = $input.first().json.body || $input.first().json;
const action = b.action;
let prompt = '';
let useWeb = false;

if (action === 'ahorro') {
  useWeb = true;
  const capital = b.capital ?? 0;
  prompt = `Busca en la web opciones ACTUALES en Mexico (anio en curso) para hacer rendir o ahorrar dinero con mayores rendimientos, para un capital aproximado de ${capital} MXN.\nConsidera: CETES / cetesdirecto, cuentas y fintech de alto rendimiento (Nu, Klar, Stori, Mercado Pago, Hey Banco, Finsus, etc.) y pagares bancarios.\nPara cada opcion dame, con vinetas: nombre, rendimiento anual aproximado (tasa), nivel de riesgo y liquidez. Cierra con una recomendacion breve segun el monto.\nResponde en espanol mexicano, usa **negritas** para nombres y tasas, e incluye de donde sale el dato.`;
} else {
  const p = b.project || {};
  const t = b.totals || {};
  const movs = (b.movements || []).join('\n');
  prompt = `Eres un asesor financiero practico que habla espanol mexicano claro y directo, sin tecnicismos. Analiza este proyecto/negocio.\n\nPROYECTO: ${p.name || 'Sin nombre'} (${p.meta || 'sin descripcion'})\nIngresos totales: ${t.in ?? 0} MXN\nEgresos totales: ${t.out ?? 0} MXN\nBalance: ${t.bal ?? 0} MXN\n\nMovimientos:\n${movs || '(sin movimientos)'}\n\nDame, con vinetas cortas y concretas:\n1. Que esta bien.\n2. Que esta mal o representa un riesgo.\n3. 2-3 recomendaciones especificas para ahorrar o mejorar el flujo de dinero.\nSe breve y directo. Usa **negritas** para lo importante. No inventes datos que no te di.`;
}

const requestBody = {
  model: useWeb ? 'gpt-4o-search-preview' : 'gpt-4o',
  max_tokens: 2000,
  messages: [{ role: 'user', content: prompt }],
};

return [{ json: { requestBody } }];

// Extrae el texto de la respuesta de OpenAI.
const data = $input.first().json;
let text = '';
if (Array.isArray(data.choices)) {
  text = data.choices.map((c) => (c.message && c.message.content) || '').join('\n\n');
}
return [{ json: { text: text || 'Sin respuesta.' } }];
